import React from "react";

const features = [
  { icon: "📦", label: "10M+ Products" },
  { icon: "🚀", label: "Fast Delivery" },
  { icon: "🔒", label: "Secure Payments" },
  { icon: "↩️", label: "Easy Returns" },
];

/* ── Desktop Sidebar ────────────────────────────────────── */
export function Sidebar() {
  return (
    <aside className="reg-sidebar">
      <div>
        <h2 style={{ fontSize: "22px", fontWeight: 700, color: "#fff", lineHeight: 1.4, marginBottom: "12px" }}>
          Looks like you're new here!
        </h2>
        <p style={{ fontSize: "13px", color: "rgba(255,255,255,.8)", lineHeight: 1.6 }}>
          Sign up with your mobile number or email to get started on ShopKart.
        </p>
        <p style={{ fontSize: "13px", color: "rgba(255,255,255,.8)", lineHeight: 1.6, marginTop: "12px" }}>
          Get access to millions of products, exclusive deals, and fast delivery across India.
        </p>
        <div style={{ display: "flex", gap: "10px", flexWrap: "wrap", marginTop: "20px" }}>
          {features.map((f) => (
            <div key={f.label} style={{
              background: "rgba(255,255,255,.15)", borderRadius: "4px",
              padding: "8px 12px", fontSize: "11px", color: "#fff",
              display: "flex", alignItems: "center", gap: "6px",
            }}>
              <span>{f.icon}</span><span>{f.label}</span>
            </div>
          ))}
        </div>
      </div>
      <div style={{ fontSize: "11px", color: "rgba(255,255,255,.5)", marginTop: "20px" }}>
        © 2026 ShopKart. All rights reserved.
      </div>
    </aside>
  );
}

/* ── Mobile / Tablet Banner (replaces sidebar) ──────────── */
export function MobileBanner() {
  return (
    <div className="reg-mobile-banner">
      {/* Left: headline */}
      <div style={{ flex: 1, minWidth: "160px" }}>
        <div style={{ fontSize: "14px", fontWeight: 700, color: "#fff" }}>
          Welcome to ShopKart 🛍
        </div>
        <div style={{ fontSize: "11px", color: "rgba(255,255,255,.75)", marginTop: "2px" }}>
          Create your account to start shopping
        </div>
      </div>

      {/* Right: feature pills — hidden on very small screens via CSS class */}
      <div className="mobile-pills-wrap" style={{ display: "flex", gap: "6px", flexWrap: "wrap" }}>
        {features.map((f) => (
          <div key={f.label} style={{
            background: "rgba(255,255,255,.2)", borderRadius: "20px",
            padding: "4px 10px", fontSize: "11px", color: "#fff", whiteSpace: "nowrap",
          }}>
            {f.icon} {f.label}
          </div>
        ))}
      </div>
    </div>
  );
}

export default Sidebar;
